**User Authentication API Endpoints**
=====================================

**Dependencies**

* `express`: `^4.17.1`
* `pg`: `^8.5.0`
* `bcrypt`: `^5.0.1`
* `jsonwebtoken`: `^9.0.0`
* `joi`: `^17.4.2`

**Database Schema**
-------------------

Assuming a PostgreSQL database with a `users` table:
```sql
CREATE TABLE users (
  id SERIAL PRIMARY KEY,
  username VARCHAR(50) NOT NULL UNIQUE,
  password VARCHAR(255) NOT NULL
);
```
**API Endpoints**
----------------

### POST /auth/register

**Register a new user**
```javascript
const express = require('express');
const router = express.Router();
const { Pool } = require('pg');
const bcrypt = require('bcrypt');
const Joi = require('joi');

const pool = new Pool({
  user: 'your_username',
  host: 'your_host',
  database: 'your_database',
  password: 'your_password',
  port: 5432,
});

const registerSchema = Joi.object({
  username: Joi.string().alphanum().min(3).max(50).required(),
  password: Joi.string().min(8).max(255).required(),
});

router.post('/auth/register', async (req, res) => {
  try {
    const { error } = registerSchema.validate(req.body);
    if (error) {
      return res.status(400).json({ message: error.details[0].message });
    }

    const { username, password } = req.body;
    const hashedPassword = await bcrypt.hash(password, 10);
    const query = {
      text: 'INSERT INTO users (username, password) VALUES ($1, $2) RETURNING *',
      values: [username, hashedPassword],
    };
    const result = await pool.query(query);
    const user = result.rows[0];
    res.json({ message: 'User created successfully' });
  } catch (error) {
    console.error(error);
    res.status(500).json({ message: 'Internal Server Error' });
  }
});
```
### POST /auth/login

**Login an existing user**
```javascript
const loginSchema = Joi.object({
  username: Joi.string().alphanum().min(3).max(50).required(),
  password: Joi.string().min(8).max(255).required(),
});

router.post('/auth/login', async (req, res) => {
  try {
    const { error } = loginSchema.validate(req.body);
    if (error) {
      return res.status(400).json({ message: error.details[0].message });
    }

    const { username, password } = req.body;
    const query = {
      text: 'SELECT * FROM users WHERE username = $1',
      values: [username],
    };
    const result = await pool.query(query);
    const user = result.rows[0];
    if (!user) {
      return res.status(401).json({ message: 'Invalid username or password' });
    }

    const isValidPassword = await bcrypt.compare(password, user.password);
    if (!isValidPassword) {
      return res.status(401).json({ message: 'Invalid username or password' });
    }

    const accessToken = jwt.sign({ userId: user.id }, process.env.ACCESS_TOKEN_SECRET, {
      expiresIn: '15m',
    });
    const refreshToken = jwt.sign({ userId: user.id }, process.env.REFRESH_TOKEN_SECRET, {
      expiresIn: '7d',
    });
    res.json({ accessToken, refreshToken });
  } catch (error) {
    console.error(error);
    res.status(500).json({ message: 'Internal Server Error' });
  }
});
```
### POST /auth/refresh

**Refresh access token**
```javascript
router.post('/auth/refresh', async (req, res) => {
  try {
    const { refreshToken } = req.body;
    if (!refreshToken) {
      return res.status(401).json({ message: 'Refresh token is required' });
    }

    const decoded = jwt.verify(refreshToken, process.env.REFRESH_TOKEN_SECRET);
    const query = {
      text: 'SELECT * FROM users WHERE id = $1',
      values: [decoded.userId],
    };
    const result = await pool.query(query);
    const user = result.rows[0];
    if (!user) {
      return res.status(401).json({ message: 'Invalid refresh token' });
    }

    const accessToken = jwt.sign({ userId: user.id }, process.env.ACCESS_TOKEN_SECRET, {
      expiresIn: '15m',
    });
    res.json({ accessToken });
  } catch (error) {
    console.error(error);
    res.status(500).json({ message: 'Internal Server Error' });
  }
});
```
**Environment Variables**

* `ACCESS_TOKEN_SECRET`: secret key for access token
* `REFRESH_TOKEN_SECRET`: secret key for refresh token

**Example Use Cases**

* Register a new user: `curl -X POST -H "Content-Type: application/json" -d '{"username": "john", "password": "password123"}' http://localhost:3000/auth/register`
* Login an existing user: `curl -X POST -H "Content-Type: application/json" -d '{"username": "john", "password": "password123"}' http://localhost:3000/auth/login`
* Refresh access token: `curl -X POST -H "Content-Type: application/json" -d '{"refreshToken": "your_refresh_token"}' http://localhost:3000/auth/refresh`

Here is a Go implementation of a distributed rate limiter using a sliding window algorithm backed by Redis:
```go
package main

import (
	"context"
	"fmt"
	"log"
	"time"

	"github.com/go-redis/redis/v8"
	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promauto"
)

const (
	defaultRedisAddr = "localhost:6379"
	defaultWindowSize = 60 * time.Second
	defaultLimit      = 100
)

type Client struct {
	id   string
	limit int
}

type RateLimiter struct {
	redisClient *redis.Client
	windowSize  time.Duration
	limit       int
	clients     map[string]Client
	metrics     *Metrics
}

type Metrics struct {
	requestsTotal prometheus.Counter
	limitExceeded prometheus.Counter
}

func NewRateLimiter(redisAddr string, windowSize time.Duration, limit int) (*RateLimiter, error) {
	redisClient := redis.NewClient(&redis.Options{
		Addr:     redisAddr,
		Password: "", // no password set
		DB:       0,  // use default DB
	})

	_, err := redisClient.Ping(context.Background()).Result()
	if err!= nil {
		return nil, err
	}

	clients := make(map[string]Client)
	metrics := &Metrics{
		requestsTotal: promauto.NewCounter(prometheus.CounterOpts{
			Name: "rate_limiter_requests_total",
			Help: "Total number of requests",
		}),
		limitExceeded: promauto.NewCounter(prometheus.CounterOpts{
			Name: "rate_limiter_limit_exceeded_total",
			Help: "Total number of requests that exceeded the limit",
		}),
	}

	return &RateLimiter{
		redisClient: redisClient,
		windowSize:  windowSize,
		limit:       limit,
		clients:     clients,
		metrics:     metrics,
	}, nil
}

func (rl *RateLimiter) Allow(clientID string) (bool, error) {
	client, ok := rl.clients[clientID]
	if!ok {
		client = Client{id: clientID, limit: rl.limit}
		rl.clients[clientID] = client
	}

	now := time.Now()
	windowStart := now.Add(-rl.windowSize)

	// Try to get the current count from Redis
	count, err := rl.redisClient.Get(context.Background(), clientID).Int64()
	if err!= nil {
		if err == redis.Nil {
			// If the key doesn't exist, start a new window
			count = 0
		} else {
			// If there's a connection error, fall back to local counting
			log.Printf("Redis connection error: %v", err)
			return rl.allowLocal(client, now, windowStart)
		}
	}

	// Check if the limit is exceeded
	if count >= client.limit {
		rl.metrics.limitExceeded.Inc()
		return false, nil
	}

	// Increment the count and update the Redis key
	err = rl.redisClient.Incr(context.Background(), clientID).Err()
	if err!= nil {
		log.Printf("Redis connection error: %v", err)
